import { AuthenticationInput, AuthenticationResponse } from '@medusajs/framework/types'
import { MedusaError } from '@medusajs/framework/utils'
import * as crypto from 'crypto'

interface AppleAuthProviderConfig {
  clientId: string
  clientSecret: string // This will be a JWT for Apple
  callbackUrl: string
  teamId?: string
  keyId?: string
  privateKey?: string
}

interface AppleUserInfo {
  sub: string
  email?: string
  email_verified?: boolean
  is_private_email?: boolean
  real_user_status?: number
}

interface AppleTokenResponse {
  access_token: string
  token_type: string
  expires_in: number
  refresh_token?: string
  id_token: string
}

/**
 * Apple OAuth2 provider for MedusaJS authentication  
 * Implements Sign in with Apple for customer authentication
 */
export class AppleAuthProvider {
  static identifier = 'apple'
  private config_: AppleAuthProviderConfig

  constructor(
    container: any,
    config: AppleAuthProviderConfig
  ) {
    this.config_ = config
  }

  async authenticate(
    data: AuthenticationInput,
    authContext: Record<string, unknown>
  ): Promise<AuthenticationResponse> {
    const { body } = data

    if (body?.grant_type === 'authorization_code') {
      return this.handleAuthorizationCode(body.code, body.state, body.user)
    }

    // Generate authorization URL for initial OAuth flow
    return this.generateAuthorizationUrl(authContext.redirectUrl as string)
  }

  private async generateAuthorizationUrl(_redirectUrl?: string): Promise<AuthenticationResponse> {
    const state = this.generateState()
    const nonce = this.generateNonce()
    
    const params = new URLSearchParams({
      client_id: this.config_.clientId,
      redirect_uri: this.config_.callbackUrl,
      response_type: 'code',
      scope: 'name email',
      response_mode: 'form_post',
      state,
      nonce
    })

    const authUrl = `https://appleid.apple.com/auth/authorize?${params.toString()}`

    return {
      success: true,
      authIdentity: undefined,
      location: authUrl
    }
  }

  private async handleAuthorizationCode(
    code: string,
    state: string,
    user?: any
  ): Promise<AuthenticationResponse> {
    try {
      // Exchange authorization code for tokens
      const tokenResponse = await this.exchangeCodeForToken(code)
      
      // Decode the ID token to get user information
      const userInfo = this.decodeIdToken(tokenResponse.id_token)

      // Apple may provide user info in the initial response
      let displayName: string | null = null
      let firstName: string | null = null
      let lastName: string | null = null

      if (user && typeof user === 'string') {
        try {
          const userData = JSON.parse(user)
          if (userData.name) {
            firstName = userData.name.firstName
            lastName = userData.name.lastName
            displayName = `${firstName} ${lastName}`.trim()
          }
        } catch (_e) {
          // Ignore parsing errors
        }
      }

      // Create authentication identity
      const authIdentity = {
        id: userInfo.sub,
        provider: 'apple',
        provider_metadata: {
          email: userInfo.email,
          email_verified: userInfo.email_verified,
          is_private_email: userInfo.is_private_email,
          real_user_status: userInfo.real_user_status,
          provider_user_id: userInfo.sub
        },
        user_metadata: {
          email: userInfo.email,
          display_name: displayName,
          given_name: firstName,
          family_name: lastName,
          avatar_url: null // Apple doesn't provide avatar
        }
      }

      return {
        success: true,
        authIdentity
      }
    } catch (error) {
      throw new MedusaError(
        MedusaError.Types.UNAUTHORIZED,
        `Apple OAuth authentication failed: ${error.message}`
      )
    }
  }

  private async exchangeCodeForToken(code: string): Promise<AppleTokenResponse> {
    const clientSecret = this.generateClientSecret()

    const response = await fetch('https://appleid.apple.com/auth/token', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: new URLSearchParams({
        client_id: this.config_.clientId,
        client_secret: clientSecret,
        code,
        grant_type: 'authorization_code',
        redirect_uri: this.config_.callbackUrl
      })
    })

    if (!response.ok) {
      const error = await response.text()
      throw new Error(`Token exchange failed: ${error}`)
    }

    return response.json()
  }

  private decodeIdToken(idToken: string): AppleUserInfo {
    try {
      // Decode JWT without verification (Apple's public key would be needed for full verification)
      const [, payload] = idToken.split('.')
      const decodedPayload = Buffer.from(payload, 'base64url').toString('utf8')
      return JSON.parse(decodedPayload)
    } catch (error) {
      throw new Error(`Failed to decode ID token: ${error.message}`)
    }
  }

  private generateClientSecret(): string {
    // For Apple, the client secret is a JWT signed with your private key
    // This is a simplified version - in production, you'd use a proper JWT library
    if (!this.config_.teamId || !this.config_.keyId || !this.config_.privateKey) {
      throw new Error('Apple OAuth requires teamId, keyId, and privateKey configuration')
    }

    const header = {
      alg: 'ES256',
      kid: this.config_.keyId
    }

    const payload = {
      iss: this.config_.teamId,
      iat: Math.floor(Date.now() / 1000),
      exp: Math.floor(Date.now() / 1000) + (86400 * 180), // 180 days
      aud: 'https://appleid.apple.com',
      sub: this.config_.clientId
    }

    // This is a simplified JWT creation - use a proper JWT library in production
    const encodedHeader = Buffer.from(JSON.stringify(header)).toString('base64url')
    const encodedPayload = Buffer.from(JSON.stringify(payload)).toString('base64url')
    const signingInput = `${encodedHeader}.${encodedPayload}`

    // Sign with ES256 (this is a placeholder - implement proper ES256 signing)
    const signature = crypto.createSign('sha256')
      .update(signingInput)
      .sign(this.config_.privateKey, 'base64url')

    return `${signingInput}.${signature}`
  }

  private generateState(): string {
    return crypto.randomBytes(16).toString('hex')
  }

  private generateNonce(): string {
    return crypto.randomBytes(16).toString('hex')
  }

  async validateCallback(
    data: AuthenticationInput,
    _authContext: Record<string, unknown>
  ): Promise<AuthenticationResponse> {
    const { body } = data

    if (body?.error) {
      throw new MedusaError(
        MedusaError.Types.UNAUTHORIZED,
        `Apple OAuth error: ${body.error}`
      )
    }

    if (!body?.code) {
      throw new MedusaError(
        MedusaError.Types.INVALID_DATA,
        'Missing authorization code in callback'
      )
    }

    return this.handleAuthorizationCode(
      body.code as string, 
      body.state as string, 
      body.user
    )
  }

  async register(
    data: AuthenticationInput,
    authContext: Record<string, unknown>
  ): Promise<AuthenticationResponse> {
    // Apple OAuth handles registration automatically during authentication
    return this.authenticate(data, authContext)
  }
}

import { ConfigModule } from '@medusajs/framework'
import { Context } from '@medusajs/framework/types'
import {
  InjectTransactionManager,
  MedusaContext,
  MedusaError,
  MedusaService
} from '@medusajs/framework/utils'

import { CustomerProfile, SocialAccountMetadata } from '../models'

type InjectedDependencies = {
  configModule: ConfigModule
}

type SocialAuthModuleConfig = {
  enabledProviders: string[]
  allowAccountLinking: boolean
  maxSocialAccountsPerCustomer: number
}

const DEFAULT_CONFIG: SocialAuthModuleConfig = {
  enabledProviders: ['google', 'microsoft', 'facebook', 'apple'],
  allowAccountLinking: true,
  maxSocialAccountsPerCustomer: 5
}

/**
 * SocialAuthService manages social authentication features for the SideDecked TCG marketplace
 * Extends MedusaJS customer authentication with OAuth social login capabilities
 */
class SocialAuthService extends MedusaService({
  CustomerProfile,
  SocialAccountMetadata
}) {
  private readonly config_: SocialAuthModuleConfig
  private readonly httpConfig_: ConfigModule['projectConfig']['http']

  constructor({ configModule }: InjectedDependencies) {
    super(...arguments)

    this.httpConfig_ = configModule.projectConfig.http

    // Get module configuration
    const moduleDef = configModule.modules?.['authentication']
    const options =
      typeof moduleDef !== 'boolean'
        ? (moduleDef?.options as SocialAuthModuleConfig)
        : null

    this.config_ = {
      ...DEFAULT_CONFIG,
      ...options
    }
  }

  /**
   * Create or update customer profile with social authentication data
   */
  @InjectTransactionManager()
  async createOrUpdateCustomerProfile(
    customerId: string,
    profileData: {
      username?: string
      displayName?: string
      avatarUrl?: string
      timezone?: string
      language?: string
      currency?: string
      profileVisibility?: 'public' | 'friends' | 'private'
      primaryAuthProvider?: string
    },
    @MedusaContext() sharedContext: Context = {}
  ): Promise<any> {
    try {
      // Try to find existing profile
      const existingProfile = await this.listCustomerProfiles(
        { customer_id: customerId },
        {},
        sharedContext
      )

      if (existingProfile.length > 0) {
        // Update existing profile
        return await this.updateCustomerProfiles(
          { id: existingProfile[0].id },
          {
            display_name: profileData.displayName,
            avatar_url: profileData.avatarUrl,
            timezone: profileData.timezone,
            language: profileData.language,
            currency: profileData.currency,
            profile_visibility: profileData.profileVisibility,
            primary_auth_provider: profileData.primaryAuthProvider,
            updated_at: new Date()
          },
          sharedContext
        )
      } else {
        // Create new profile
        return await this.createCustomerProfiles(
          {
            customer_id: customerId,
            username: profileData.username,
            display_name: profileData.displayName,
            avatar_url: profileData.avatarUrl,
            timezone: profileData.timezone || 'UTC',
            language: profileData.language || 'en',
            currency: profileData.currency || 'USD',
            profile_visibility: profileData.profileVisibility || 'public',
            primary_auth_provider: profileData.primaryAuthProvider,
            social_accounts_count: 0,
            email_verified: false,
            phone_verified: false,
            login_count: 0
          },
          sharedContext
        )
      }
    } catch (error) {
      throw new MedusaError(
        MedusaError.Types.INVALID_DATA,
        `Failed to create or update customer profile: ${error.message}`
      )
    }
  }

  /**
   * Link a social account to a customer
   */
  @InjectTransactionManager()
  async linkSocialAccount(
    customerId: string,
    providerIdentityId: string,
    socialAccountData: {
      provider: 'google' | 'microsoft' | 'facebook' | 'apple'
      providerUserId: string
      email?: string
      displayName?: string
      avatarUrl?: string
      profileUrl?: string
      scopesGranted?: string[]
      tokenExpiresAt?: Date
      locale?: string
      timezone?: string
      isVerified?: boolean
    },
    @MedusaContext() sharedContext: Context = {}
  ): Promise<any> {
    // Check if provider is enabled
    if (!this.config_.enabledProviders.includes(socialAccountData.provider)) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        `Provider ${socialAccountData.provider} is not enabled`
      )
    }

    // Check if account linking is allowed
    if (!this.config_.allowAccountLinking) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        'Account linking is not allowed'
      )
    }

    // Check maximum social accounts limit
    const existingAccounts = await this.listSocialAccountMetadatas(
      { customer_id: customerId, is_active: true },
      {},
      sharedContext
    )

    if (existingAccounts.length >= this.config_.maxSocialAccountsPerCustomer) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        `Maximum ${this.config_.maxSocialAccountsPerCustomer} social accounts per customer exceeded`
      )
    }

    // Check if this provider account is already linked
    const existingProviderAccount = await this.listSocialAccountMetadatas(
      {
        customer_id: customerId,
        provider: socialAccountData.provider,
        provider_user_id: socialAccountData.providerUserId
      },
      {},
      sharedContext
    )

    if (existingProviderAccount.length > 0) {
      throw new MedusaError(
        MedusaError.Types.DUPLICATE_ERROR,
        `${socialAccountData.provider} account is already linked to this customer`
      )
    }

    // Create social account metadata
    const socialAccount = await this.createSocialAccountMetadatas(
      {
        customer_id: customerId,
        provider_identity_id: providerIdentityId,
        provider: socialAccountData.provider,
        provider_user_id: socialAccountData.providerUserId,
        email: socialAccountData.email,
        display_name: socialAccountData.displayName,
        avatar_url: socialAccountData.avatarUrl,
        profile_url: socialAccountData.profileUrl,
        is_primary: existingAccounts.length === 0, // First account is primary
        token_expires_at: socialAccountData.tokenExpiresAt,
        scopes_granted: socialAccountData.scopesGranted ? JSON.stringify(socialAccountData.scopesGranted) : null,
        locale: socialAccountData.locale,
        timezone: socialAccountData.timezone,
        is_verified: socialAccountData.isVerified || false,
        last_used_at: new Date()
      },
      sharedContext
    )

    // Update customer profile social account count
    const customerProfiles = await this.listCustomerProfiles(
      { customer_id: customerId },
      {},
      sharedContext
    )

    if (customerProfiles.length > 0) {
      await this.updateCustomerProfiles(
        { id: customerProfiles[0].id },
        {
          social_accounts_count: existingAccounts.length + 1,
          social_display_name: socialAccountData.displayName,
          social_avatar_url: socialAccountData.avatarUrl
        },
        sharedContext
      )
    }

    return socialAccount
  }

  /**
   * Set primary social account for a customer
   */
  @InjectTransactionManager()
  async setPrimarySocialAccount(
    customerId: string,
    socialAccountId: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<any> {
    // Verify the social account belongs to the customer
    const socialAccount = await this.retrieveSocialAccountMetadata(
      socialAccountId,
      {},
      sharedContext
    )

    if (socialAccount.customer_id !== customerId) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        'Social account does not belong to customer'
      )
    }

    // Remove primary flag from all other accounts
    const allAccounts = await this.listSocialAccountMetadatas(
      { customer_id: customerId },
      {},
      sharedContext
    )

    for (const account of allAccounts) {
      if (account.id !== socialAccountId && account.is_primary) {
        await this.updateSocialAccountMetadatas(
          { id: account.id },
          { is_primary: false },
          sharedContext
        )
      }
    }

    // Set the specified account as primary
    return await this.updateSocialAccountMetadatas(
      { id: socialAccountId },
      { is_primary: true },
      sharedContext
    )
  }

  /**
   * Unlink a social account from a customer
   */
  @InjectTransactionManager()
  async unlinkSocialAccount(
    customerId: string,
    socialAccountId: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<void> {
    // Verify the social account belongs to the customer
    const socialAccount = await this.retrieveSocialAccountMetadata(
      socialAccountId,
      {},
      sharedContext
    )

    if (socialAccount.customer_id !== customerId) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        'Social account does not belong to customer'
      )
    }

    // Check if this is the only authentication method
    const allAccounts = await this.listSocialAccountMetadatas(
      { customer_id: customerId, is_active: true },
      {},
      sharedContext
    )

    if (allAccounts.length === 1) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        'Cannot unlink the only authentication method. Please add another authentication method first.'
      )
    }

    // Mark account as inactive instead of deleting
    await this.updateSocialAccountMetadatas(
      { id: socialAccountId },
      { is_active: false },
      sharedContext
    )

    // Update customer profile social account count
    const customerProfiles = await this.listCustomerProfiles(
      { customer_id: customerId },
      {},
      sharedContext
    )

    if (customerProfiles.length > 0) {
      await this.updateCustomerProfiles(
        { id: customerProfiles[0].id },
        {
          social_accounts_count: allAccounts.length - 1
        },
        sharedContext
      )
    }

    // If this was the primary account, set another account as primary
    if (socialAccount.is_primary && allAccounts.length > 1) {
      const remainingAccounts = allAccounts.filter(
        account => account.id !== socialAccountId && account.is_active
      )
      
      if (remainingAccounts.length > 0) {
        await this.setPrimarySocialAccount(
          customerId,
          remainingAccounts[0].id,
          sharedContext
        )
      }
    }
  }

  /**
   * Update login activity for a customer
   */
  @InjectTransactionManager()
  async updateLoginActivity(
    customerId: string,
    socialAccountId?: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<void> {
    // Update customer profile login activity
    const customerProfiles = await this.listCustomerProfiles(
      { customer_id: customerId },
      {},
      sharedContext
    )

    if (customerProfiles.length > 0) {
      await this.updateCustomerProfiles(
        { id: customerProfiles[0].id },
        {
          last_login_at: new Date(),
          login_count: customerProfiles[0].login_count + 1
        },
        sharedContext
      )
    }

    // Update social account last used
    if (socialAccountId) {
      await this.updateSocialAccountMetadatas(
        { id: socialAccountId },
        { last_used_at: new Date() },
        sharedContext
      )
    }
  }

  /**
   * Get customer's social accounts summary
   */
  async getCustomerSocialAccountsSummary(
    customerId: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<{
    totalAccounts: number
    providers: string[]
    primaryProvider: string | null
    accounts: any[]
  }> {
    const socialAccounts = await this.listSocialAccountMetadatas(
      { customer_id: customerId, is_active: true },
      {},
      sharedContext
    )

    const primaryAccount = socialAccounts.find(account => account.is_primary)
    
    return {
      totalAccounts: socialAccounts.length,
      providers: [...new Set(socialAccounts.map(account => account.provider))],
      primaryProvider: primaryAccount?.provider || null,
      accounts: socialAccounts.map(account => ({
        id: account.id,
        provider: account.provider,
        displayName: account.display_name,
        email: account.email,
        avatarUrl: account.avatar_url,
        isPrimary: account.is_primary,
        isVerified: account.is_verified,
        connectedAt: account.connected_at,
        lastUsedAt: account.last_used_at
      }))
    }
  }
}

export default SocialAuthService

import { ConfigModule } from '@medusajs/framework'
import { Context } from '@medusajs/framework/types'
import {
  InjectTransactionManager,
  MedusaContext,
  MedusaError,
  MedusaService
} from '@medusajs/framework/utils'

import { CustomerProfile, SocialAccountMetadata, RefreshToken } from '../models'
import { emitAuthEvent, AuthEventType } from './auth-event-emitter'

type InjectedDependencies = {
  configModule: ConfigModule
}

/**
 * Social Account Management Service
 * Handles linking, unlinking, and managing customer social accounts.
 * Also manages refresh tokens for JWT session management.
 */
class SocialAccountManagementService extends MedusaService({
  CustomerProfile,
  SocialAccountMetadata,
  RefreshToken
}) {
  private readonly config_: ConfigModule

  constructor({ configModule }: InjectedDependencies) {
    super(...arguments)
    this.config_ = configModule
  }

  /**
   * Process OAuth callback and create/link social account
   */
  @InjectTransactionManager()
  async processOAuthCallback(
    authData: {
      provider: 'google' | 'github' | 'microsoft' | 'facebook' | 'apple'
      providerUserId: string
      email?: string
      displayName?: string
      avatarUrl?: string
      accessToken?: string
      refreshToken?: string
      expiresAt?: Date
      userMetadata?: Record<string, any>
    },
    existingCustomerId?: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<{
    customerId: string
    socialAccountId: string
    isNewCustomer: boolean
    isNewSocialAccount: boolean
  }> {
    let customerId = existingCustomerId
    let isNewCustomer = false
    let isNewSocialAccount = false

    // Check if this social account already exists
    const existingSocialAccounts = await this.listSocialAccountMetadatas(
      {
        provider: authData.provider,
        provider_user_id: authData.providerUserId
      },
      {},
      sharedContext
    )

    if (existingSocialAccounts.length > 0) {
      // Social account already exists - use existing customer
      const existingSocialAccount = existingSocialAccounts[0]
      customerId = existingSocialAccount.customer_id

      // Update last used timestamp
      await this.updateSocialAccountMetadatas(
        { id: existingSocialAccount.id },
        {
          last_used_at: new Date(),
          token_expires_at: authData.expiresAt
        },
        sharedContext
      )

      return {
        customerId,
        socialAccountId: existingSocialAccount.id,
        isNewCustomer: false,
        isNewSocialAccount: false
      }
    }

    // If no existing customer ID and email provided, try to find customer by email
    if (!customerId && authData.email) {
      // This would require access to the customer module to find by email
      // For now, we'll create a new customer profile
      // In a real implementation, you'd query the MedusaJS customer module
    }

    // If still no customer ID, this will be a new customer
    if (!customerId) {
      // Generate a new customer ID (this would normally be handled by MedusaJS customer creation)
      customerId = `cus_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
      isNewCustomer = true
    }

    // Create customer profile if new customer
    if (isNewCustomer) {
      await this.createCustomerProfiles(
        {
          customer_id: customerId,
          display_name: authData.displayName,
          avatar_url: authData.avatarUrl,
          social_display_name: authData.displayName,
          social_avatar_url: authData.avatarUrl,
          primary_auth_provider: authData.provider,
          social_accounts_count: 1,
          email_verified: true, // OAuth emails are typically verified
          login_count: 1,
          last_login_at: new Date()
        },
        sharedContext
      )
    }

    // Create social account metadata
    const socialAccount = await this.createSocialAccountMetadatas(
      {
        customer_id: customerId,
        provider_identity_id: `pi_${authData.provider}_${authData.providerUserId}`,
        provider: authData.provider,
        provider_user_id: authData.providerUserId,
        email: authData.email,
        display_name: authData.displayName,
        avatar_url: authData.avatarUrl,
        is_primary: true, // First or only social account is primary
        token_expires_at: authData.expiresAt,
        locale: authData.userMetadata?.locale,
        timezone: authData.userMetadata?.timezone,
        is_verified: true,
        last_used_at: new Date()
      },
      sharedContext
    )

    isNewSocialAccount = true

    return {
      customerId,
      socialAccountId: socialAccount.id,
      isNewCustomer,
      isNewSocialAccount
    }
  }

  /**
   * Get customer's complete social account profile
   */
  async getCustomerSocialProfile(
    customerId: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<{
    profile: any | null
    socialAccounts: any[]
    primaryProvider: string | null
    accountsSummary: {
      total: number
      byProvider: Record<string, number>
      verifiedCount: number
    }
  }> {
    // Get customer profile
    const profiles = await this.listCustomerProfiles(
      { customer_id: customerId },
      {},
      sharedContext
    )
    const profile = profiles[0] || null

    // Get all social accounts
    const socialAccounts = await this.listSocialAccountMetadatas(
      { customer_id: customerId, is_active: true },
      {},
      sharedContext
    )

    // Calculate summary
    const byProvider: Record<string, number> = {}
    let verifiedCount = 0
    let primaryProvider: string | null = null

    socialAccounts.forEach(account => {
      byProvider[account.provider] = (byProvider[account.provider] || 0) + 1
      if (account.is_verified) verifiedCount++
      if (account.is_primary) primaryProvider = account.provider
    })

    return {
      profile,
      socialAccounts: socialAccounts.map(account => ({
        id: account.id,
        provider: account.provider,
        displayName: account.display_name,
        email: account.email,
        avatarUrl: account.avatar_url,
        isPrimary: account.is_primary,
        isVerified: account.is_verified,
        connectedAt: account.connected_at,
        lastUsedAt: account.last_used_at
      })),
      primaryProvider,
      accountsSummary: {
        total: socialAccounts.length,
        byProvider,
        verifiedCount
      }
    }
  }

  /**
   * Update customer social preferences
   */
  @InjectTransactionManager()
  async updateCustomerSocialPreferences(
    customerId: string,
    preferences: {
      profileVisibility?: 'public' | 'friends' | 'private'
      showCollectionValue?: boolean
      allowTradeRequests?: boolean
      timezone?: string
      language?: string
      currency?: string
    },
    @MedusaContext() sharedContext: Context = {}
  ): Promise<any> {
    const profiles = await this.listCustomerProfiles(
      { customer_id: customerId },
      {},
      sharedContext
    )

    if (profiles.length === 0) {
      throw new MedusaError(
        MedusaError.Types.NOT_FOUND,
        'Customer profile not found'
      )
    }

    return await this.updateCustomerProfiles(
      { id: profiles[0].id },
      {
        profile_visibility: preferences.profileVisibility,
        show_collection_value: preferences.showCollectionValue,
        allow_trade_requests: preferences.allowTradeRequests,
        timezone: preferences.timezone,
        language: preferences.language,
        currency: preferences.currency,
        updated_at: new Date()
      },
      sharedContext
    )
  }

  /**
   * Disconnect a social account
   */
  @InjectTransactionManager()
  async disconnectSocialAccount(
    customerId: string,
    socialAccountId: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<void> {
    // Verify ownership
    const socialAccount = await this.retrieveSocialAccountMetadata(
      socialAccountId,
      {},
      sharedContext
    )

    if (socialAccount.customer_id !== customerId) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        'Social account does not belong to customer'
      )
    }

    // Check if this is the only authentication method
    const allAccounts = await this.listSocialAccountMetadatas(
      { customer_id: customerId, is_active: true },
      {},
      sharedContext
    )

    if (allAccounts.length === 1) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        'Cannot disconnect the only authentication method'
      )
    }

    // Deactivate the social account
    await this.updateSocialAccountMetadatas(
      { id: socialAccountId },
      { is_active: false },
      sharedContext
    )

    // Update customer profile
    const profiles = await this.listCustomerProfiles(
      { customer_id: customerId },
      {},
      sharedContext
    )

    if (profiles.length > 0) {
      await this.updateCustomerProfiles(
        { id: profiles[0].id },
        {
          social_accounts_count: allAccounts.length - 1,
          updated_at: new Date()
        },
        sharedContext
      )
    }

    // If this was the primary account, set another as primary
    if (socialAccount.is_primary) {
      const remainingAccounts = allAccounts.filter(
        account => account.id !== socialAccountId && account.is_active
      )

      if (remainingAccounts.length > 0) {
        await this.updateSocialAccountMetadatas(
          { id: remainingAccounts[0].id },
          { is_primary: true },
          sharedContext
        )

        // Update customer profile primary provider
        if (profiles.length > 0) {
          await this.updateCustomerProfiles(
            { id: profiles[0].id },
            { primary_auth_provider: remainingAccounts[0].provider },
            sharedContext
          )
        }
      }
    }
  }

  /**
   * Refresh social account token
   */
  @InjectTransactionManager()
  async refreshSocialAccountToken(
    socialAccountId: string,
    newTokenData: {
      accessToken: string
      refreshToken?: string
      expiresAt?: Date
    },
    @MedusaContext() sharedContext: Context = {}
  ): Promise<any> {
    return await this.updateSocialAccountMetadatas(
      { id: socialAccountId },
      {
        token_expires_at: newTokenData.expiresAt,
        last_used_at: new Date()
      },
      sharedContext
    )
  }

  /**
   * Get social accounts that need token refresh
   */
  async getAccountsNeedingRefresh(
    @MedusaContext() sharedContext: Context = {}
  ): Promise<any[]> {
    const expiryThreshold = new Date(Date.now() + 24 * 60 * 60 * 1000) // 24 hours from now

    return await this.listSocialAccountMetadatas(
      {
        is_active: true,
        token_expires_at: { $lt: expiryThreshold }
      },
      {},
      sharedContext
    )
  }

  /**
   * Set primary social account for a customer
   */
  @InjectTransactionManager()
  async setPrimarySocialAccount(
    customerId: string,
    socialAccountId: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<any> {
    // Verify the social account belongs to the customer
    const socialAccount = await this.retrieveSocialAccountMetadata(
      socialAccountId,
      {},
      sharedContext
    )

    if (socialAccount.customer_id !== customerId) {
      throw new MedusaError(
        MedusaError.Types.NOT_ALLOWED,
        'Social account does not belong to customer'
      )
    }

    // Remove primary flag from all other accounts
    const allAccounts = await this.listSocialAccountMetadatas(
      { customer_id: customerId },
      {},
      sharedContext
    )

    for (const account of allAccounts) {
      if (account.id !== socialAccountId && account.is_primary) {
        await this.updateSocialAccountMetadatas(
          { id: account.id },
          { is_primary: false },
          sharedContext
        )
      }
    }

    // Set the specified account as primary
    return await this.updateSocialAccountMetadatas(
      { id: socialAccountId },
      { is_primary: true },
      sharedContext
    )
  }

  // ── Refresh Token Methods ───────────────────────────────────────────

  /**
   * Generate a new refresh token for a customer.
   * Returns the raw token (to send to client) — only the hash is stored.
   */
  @InjectTransactionManager()
  async generateRefreshToken(
    customerId: string,
    deviceInfo?: {
      ipAddress?: string
      userAgent?: string
      deviceName?: string
    },
    @MedusaContext() sharedContext: Context = {}
  ): Promise<{ rawToken: string; refreshToken: any }> {
    const crypto = await import('crypto')
    const rawToken = crypto.randomUUID()
    const tokenHash = crypto.createHash('sha256').update(rawToken).digest('hex')

    const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000) // 30 days

    const refreshToken = await this.createRefreshTokens(
      {
        customer_id: customerId,
        token_hash: tokenHash,
        expires_at: expiresAt,
        ip_address: deviceInfo?.ipAddress || undefined,
        user_agent: deviceInfo?.userAgent || undefined,
        device_info: deviceInfo?.deviceName || undefined
      },
      sharedContext
    )

    return { rawToken, refreshToken }
  }

  /**
   * Validate a refresh token and rotate it (single-use).
   * Returns new raw token + new DB record. Old token is revoked.
   * Throws if token is invalid, expired, or already revoked.
   */
  @InjectTransactionManager()
  async validateAndRotateRefreshToken(
    rawToken: string,
    deviceInfo?: {
      ipAddress?: string
      userAgent?: string
      deviceName?: string
    },
    @MedusaContext() sharedContext: Context = {}
  ): Promise<{ rawToken: string; refreshToken: any; customerId: string }> {
    const crypto = await import('crypto')
    const tokenHash = crypto.createHash('sha256').update(rawToken).digest('hex')

    const existingTokens = await this.listRefreshTokens(
      { token_hash: tokenHash },
      {},
      sharedContext
    )

    if (existingTokens.length === 0) {
      throw new MedusaError(
        MedusaError.Types.UNAUTHORIZED,
        'Invalid refresh token'
      )
    }

    const existingToken = existingTokens[0]

    if (existingToken.revoked_at) {
      // Revoked token reuse indicates potential theft — revoke entire token family
      await this.revokeAllRefreshTokensForCustomer(
        existingToken.customer_id,
        undefined,
        sharedContext
      )
      emitAuthEvent({
        customer_id: existingToken.customer_id,
        event_type: AuthEventType.SESSION_TERMINATED,
        metadata: { reason: 'refresh_token_reuse_detected' }
      })
      throw new MedusaError(
        MedusaError.Types.UNAUTHORIZED,
        'Refresh token has been revoked'
      )
    }

    if (new Date(existingToken.expires_at) < new Date()) {
      throw new MedusaError(
        MedusaError.Types.UNAUTHORIZED,
        'Refresh token has expired'
      )
    }

    // Revoke old token
    await this.updateRefreshTokens(
      { id: existingToken.id },
      { revoked_at: new Date() },
      sharedContext
    )

    // Generate new token pair
    const { rawToken: newRawToken, refreshToken: newRefreshToken } =
      await this.generateRefreshToken(
        existingToken.customer_id,
        deviceInfo,
        sharedContext
      )

    return {
      rawToken: newRawToken,
      refreshToken: newRefreshToken,
      customerId: existingToken.customer_id
    }
  }

  /**
   * Revoke a single refresh token by its raw value.
   */
  @InjectTransactionManager()
  async revokeRefreshToken(
    rawToken: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<void> {
    const crypto = await import('crypto')
    const tokenHash = crypto.createHash('sha256').update(rawToken).digest('hex')

    const existingTokens = await this.listRefreshTokens(
      { token_hash: tokenHash },
      {},
      sharedContext
    )

    if (existingTokens.length > 0) {
      await this.updateRefreshTokens(
        { id: existingTokens[0].id },
        { revoked_at: new Date() },
        sharedContext
      )
    }
  }

  /**
   * Revoke all refresh tokens for a customer.
   * Optionally excludes a specific token (e.g., the current session).
   * Returns the count of tokens revoked.
   */
  @InjectTransactionManager()
  async revokeAllRefreshTokensForCustomer(
    customerId: string,
    exceptTokenHash?: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<number> {
    const activeTokens = await this.listRefreshTokens(
      {
        customer_id: customerId,
        revoked_at: null
      },
      {},
      sharedContext
    )

    let revokedCount = 0
    for (const token of activeTokens) {
      if (exceptTokenHash && token.token_hash === exceptTokenHash) {
        continue
      }
      await this.updateRefreshTokens(
        { id: token.id },
        { revoked_at: new Date() },
        sharedContext
      )
      revokedCount++
    }

    return revokedCount
  }

  /**
   * Returns the platform_role for a customer, or null if not set.
   * Used to enrich JWT app_metadata at login and token refresh time.
   */
  async getCustomerPlatformRole(
    customerId: string,
    @MedusaContext() sharedContext: Context = {}
  ): Promise<string | null> {
    const profiles = await this.listCustomerProfiles(
      { customer_id: customerId },
      { select: ['platform_role'] },
      sharedContext
    )
    return profiles[0]?.platform_role ?? null
  }

  /**
   * Revoke all other sessions for a customer, keeping the current one active.
   * Hashes the current raw refresh token to identify the session to preserve.
   */
  async revokeOtherSessions(
    customerId: string,
    currentRawToken?: string
  ): Promise<number> {
    let exceptTokenHash: string | undefined
    if (currentRawToken) {
      const crypto = await import('crypto')
      exceptTokenHash = crypto.createHash('sha256').update(currentRawToken).digest('hex')
    }
    return this.revokeAllRefreshTokensForCustomer(customerId, exceptTokenHash)
  }
}

