import { NextRequest, NextResponse } from 'next/server'
import { setAuthToken } from '@/lib/data/cookies'

function isValidRelativePath(url: string | undefined): url is string {
  if (!url) return false
  return (
    url.startsWith('/') &&
    !url.startsWith('//') &&   // reject protocol-relative URLs like //evil.com
    !url.startsWith('\\') &&  // reject backslash-prefixed paths
    !url.includes('://') &&   // reject full URLs with a scheme
    !url.includes('\\')       // reject any backslashes in the path
  )
}

export async function GET(request: NextRequest) {
  const searchParams = request.nextUrl.searchParams
  const token = searchParams.get('token')
  const error = searchParams.get('message')

  const baseUrl = process.env.NEXT_PUBLIC_BASE_URL ||
    `${request.nextUrl.protocol}//${request.nextUrl.host}`

  if (error) {
    console.error('Authentication error:', error)
    return NextResponse.redirect(new URL(`/user?error=${encodeURIComponent(error)}`, baseUrl))
  }

  if (token) {
    try {
      await setAuthToken(token)

      let redirectPath = '/user'
      const rawReturnUrl = request.cookies.get('_sd_return_url')?.value
      if (rawReturnUrl) {
        try {
          const decodedReturnUrl = decodeURIComponent(rawReturnUrl)
          if (isValidRelativePath(decodedReturnUrl)) {
            redirectPath = decodedReturnUrl
          }
        } catch {
          console.warn('Invalid _sd_return_url cookie, falling back to /user')
        }
      }

      const response = NextResponse.redirect(new URL(redirectPath, baseUrl))

      // Clear the return URL cookie
      response.cookies.set('_sd_return_url', '', { maxAge: 0, path: '/' })

      return response
    } catch (err: unknown) {
      console.error('Error setting authentication cookies:', err)
      return NextResponse.redirect(new URL(`/user?error=${encodeURIComponent('Cookie setup failed')}`, baseUrl))
    }
  } else {
    console.error('No token received in OAuth callback')
    return NextResponse.redirect(new URL('/user?error=No%20authentication%20token%20received', baseUrl))
  }
}

