// Separate component to handle OAuth errors in the login form
function LoginFormWithErrors({
  oauthError,
  provider,
  message,
  retrieveError,
}: {
  oauthError?: string
  provider?: string
  message?: string
  retrieveError?: string | null
}) {
  const getErrorMessage = () => {
    if (retrieveError) {
      return retrieveError
    }

    switch (oauthError) {
      case "invalid_provider":
        return "Invalid OAuth provider selected."
      case "access_denied":
        return `Access was denied for ${provider} authentication. Please try again.`
      case "missing_parameters":
        return `Missing required parameters from ${provider}. Please try again.`
      case "auth_failed":
        return message || `Authentication with ${provider} failed. Please try again.`
      case "oauth_error":
        return message || `An error occurred with ${provider} authentication.`
      case "server_error":
        return message || "A server error occurred during authentication."
      case "missing_token":
        return `Authentication with ${provider} succeeded but no token was received. Please try again.`
      case "unexpected_response":
        return `Unexpected response from ${provider} authentication. Please try again.`
      default:
        if (message) {
          return decodeURIComponent(message)
        }
        return null
    }
  }

  const errorMessage = getErrorMessage()

  return (
    <div>
      {errorMessage && (
        <div className="max-w-md mx-auto mt-6 px-4">
          <div
            className="flex items-start gap-3 p-4 rounded-[14px] mb-6"
            style={{
              background: "rgba(239, 68, 68, 0.06)",
              border: "1px solid rgba(239, 68, 68, 0.2)",
            }}
          >
            <span className="text-lg shrink-0" style={{ color: "var(--negative, #EF4444)" }}>&#10005;</span>
            <div>
              <p className="text-sm font-medium" style={{ color: "var(--text-primary, #F0EEFF)" }}>
                Authentication Error
              </p>
              <p className="text-sm mt-1" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
                {errorMessage}
              </p>
            </div>
          </div>
        </div>
      )}
      <LoginForm />
    </div>
  )
}

