import { MedusaRequest, MedusaResponse } from '@medusajs/framework/http'
import {
  Modules,
  MedusaError
} from '@medusajs/framework/utils'

/**
 * Initiates OAuth authentication flow for customers
 */
export const GET = async (req: MedusaRequest, res: MedusaResponse) => {
  const { auth_provider } = req.params
  const authService = req.scope.resolve(Modules.AUTH)
  
  console.log(`Initiating OAuth for provider: ${auth_provider}`)

  const authData = {
    url: req.url,
    headers: req.headers as Record<string, string>,
    query: req.query as Record<string, string>,
    body: req.body as Record<string, string> | undefined,
    protocol: req.protocol,
  }

  try {
    // Initiate OAuth flow
    const { success, error, location } = await authService.authenticate(
      auth_provider,
      authData
    )

    if (location) {
      console.log(`Redirecting to OAuth provider: ${location}`)
      return res.status(200).json({ location })
    }

    if (!success) {
      throw new MedusaError(
        MedusaError.Types.UNAUTHORIZED,
        error || 'Failed to initiate authentication'
      )
    }

    // Should not reach here for OAuth providers
    throw new MedusaError(
      MedusaError.Types.INVALID_DATA,
      'Invalid OAuth flow'
    )
  } catch (error) {
    console.error('OAuth initiation error:', error)
    throw error
  }
}

