import { redirect } from "next/navigation"
import { cookies } from "next/headers"
import { loginWithOAuth, registerWithOAuth } from "@/lib/data/customer"
import { sdk } from "@/lib/config"

export type OAuthProvider = "google" | "discord" | "microsoft"

/**
 * Initiates OAuth login flow - Two-step process:
 * 1. Server calls backend with proper headers to get OAuth provider URL
 * 2. Redirect browser to the OAuth provider URL (Google, GitHub, etc.)
 */
export async function initiateOAuthLogin(
  provider: OAuthProvider,
  returnUrl?: string
): Promise<never> {
  try {
    // Get required configuration
    const backendUrl = process.env.MEDUSA_BACKEND_URL || 'http://localhost:9000'
    const publishableKey = process.env.NEXT_PUBLIC_MEDUSA_PUBLISHABLE_KEY
    const baseUrl = process.env.NEXT_PUBLIC_BASE_URL || 'http://localhost:3000'
    
    if (!publishableKey) {
      throw new Error('NEXT_PUBLIC_MEDUSA_PUBLISHABLE_KEY is required for OAuth')
    }
    
    // Step 1: Server calls backend with proper headers and callback URL
    // Use callback_url to override the default callbackUrl and point to storefront
    const storefrontCallbackUrl = `${baseUrl}/auth/callback`
    const params = new URLSearchParams({
      callback_url: storefrontCallbackUrl,
    })
    
    // Add return URL if provided (for post-authentication redirect)
    if (returnUrl) {
      params.set('return_url', returnUrl)
    }
    
    const backendOAuthUrl = `${backendUrl}/auth/customer/${provider}?${params.toString()}`
    
    console.log('OAuth Initiation Debug:')
    console.log('- Provider:', provider)
    console.log('- Backend URL:', backendUrl)
    console.log('- Publishable Key:', publishableKey ? `${publishableKey.slice(0, 20)}...` : 'NOT SET')
    console.log('- Storefront Callback URL:', storefrontCallbackUrl)
    console.log('- Full Backend OAuth URL:', backendOAuthUrl)
    
    // Make server-side request WITH required headers
    const response = await fetch(backendOAuthUrl, {
      method: 'GET',
      headers: {
        'x-publishable-api-key': publishableKey,
        'Accept': 'application/json',
      },
      redirect: 'manual' // Don't follow redirects automatically
    })
    
    console.log('Backend Response Debug:')
    console.log('- Status:', response.status)
    console.log('- Status Text:', response.statusText)
    console.log('- Headers:', Object.fromEntries(response.headers.entries()))
    
    // Log response body for debugging
    const responseText = await response.text()
    console.log('- Response Body:', responseText)
    
    // Step 2: Extract OAuth provider URL from backend response
    let oauthProviderUrl: string | null = null
    
    // Check for redirect response (3xx status)
    if (response.status >= 300 && response.status < 400) {
      oauthProviderUrl = response.headers.get('location')
      console.log('- Found redirect location:', oauthProviderUrl)
    }
    
    // Check for JSON response with URL
    if (!oauthProviderUrl && response.headers.get('content-type')?.includes('application/json')) {
      try {
        const data = JSON.parse(responseText)
        oauthProviderUrl = data.location || data.url || data.redirect_url
        console.log('- Found JSON URL:', oauthProviderUrl)
      } catch (jsonError) {
        console.warn('- Failed to parse JSON response:', jsonError)
      }
    }
    
    // Check for plain text response
    if (!oauthProviderUrl && responseText.startsWith('http')) {
      oauthProviderUrl = responseText.trim()
      console.log('- Found text URL:', oauthProviderUrl)
    }
    
    if (!oauthProviderUrl) {
      console.error('OAuth URL Extraction Failed:')
      console.error('- No valid OAuth URL found in response')
      console.error('- Response status:', response.status)
      console.error('- Response body:', responseText)
      
      throw new Error(`Backend did not return a valid OAuth URL. Status: ${response.status}. Response: ${responseText}`)
    }
    
    console.log('OAuth Success - Redirecting to provider:', oauthProviderUrl)
    
    // Step 3: Redirect browser to the OAuth provider (Google, GitHub, etc.)
    redirect(oauthProviderUrl)
    
  } catch (error: any) {
    // NEXT_REDIRECT is expected when redirect() is called - don't treat as error
    if (error.message === 'NEXT_REDIRECT') {
      console.log('OAuth redirect successful - user being sent to OAuth provider')
      throw error // Re-throw to complete the redirect
    }
    
    console.error('OAuth initiation error:', error)
    console.error('Error stack:', error.stack)
    throw new Error(`Failed to initiate OAuth with ${provider}: ${error.message}`)
  }
}

/**
 * Handles OAuth callback from provider
 * Note: MedusaJS handles OAuth state validation internally, so we rely on that
 */
export async function handleOAuthCallback(
  provider: OAuthProvider,
  code: string,
  state: string
): Promise<{ success: boolean; returnUrl?: string; error?: string }> {
  try {
    console.log('OAuth Callback Debug:')
    console.log('- Provider:', provider)
    console.log('- Code:', code ? `${code.slice(0, 20)}...` : 'NOT PROVIDED')
    console.log('- State:', state ? `${state.slice(0, 40)}...` : 'NOT PROVIDED')

    // Use the customer data layer OAuth login function
    // MedusaJS will handle state validation internally for security
    console.log('Attempting OAuth login with backend...')
    const result = await loginWithOAuth(provider, { code, state })
    
    console.log('OAuth login result:', result)
    
    if (result.success) {
      console.log('OAuth authentication successful')
      return { 
        success: true, 
        returnUrl: '/user'
      }
    }

    console.error('OAuth authentication failed:', result.error)
    return { success: false, error: result.error || 'Failed to authenticate with OAuth provider' }
  } catch (error: any) {
    console.error(`OAuth ${provider} callback error:`, error)
    console.error('Error stack:', error.stack)
    return { 
      success: false, 
      error: error.message || 'OAuth authentication failed' 
    }
  }
}

/**
 * Links a social account to existing authenticated customer
 */
export async function linkSocialAccount(
  provider: OAuthProvider,
  socialData: {
    provider_user_id: string
    email?: string
    display_name?: string
    avatar_url?: string
    access_token?: string
    refresh_token?: string
    expires_at?: string
  }
): Promise<{ success: boolean; error?: string }> {
  try {
    const publishableKey = process.env.NEXT_PUBLIC_MEDUSA_PUBLISHABLE_KEY
    
    if (!publishableKey) {
      return { 
        success: false, 
        error: 'NEXT_PUBLIC_MEDUSA_PUBLISHABLE_KEY is required' 
      }
    }

    const response = await fetch(
      `${process.env.MEDUSA_BACKEND_URL || 'http://localhost:9000'}/store/auth/social/link`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-publishable-api-key': publishableKey,
          // Add authentication headers from cookies
          'Cookie': (await cookies()).toString(),
        },
        body: JSON.stringify({
          provider,
          ...socialData,
        }),
      }
    )

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}))
      return { 
        success: false, 
        error: errorData.message || 'Failed to link social account' 
      }
    }

    return { success: true }
  } catch (error: any) {
    console.error('Link social account error:', error)
    return { 
      success: false, 
      error: error.message || 'Failed to link social account' 
    }
  }
}

/**
 * Gets customer's linked social accounts
 */
export async function getLinkedSocialAccounts(): Promise<{
  success: boolean
  data?: any
  error?: string
}> {
  try {
    const publishableKey = process.env.NEXT_PUBLIC_MEDUSA_PUBLISHABLE_KEY
    
    if (!publishableKey) {
      return { 
        success: false, 
        error: 'NEXT_PUBLIC_MEDUSA_PUBLISHABLE_KEY is required' 
      }
    }

    const response = await fetch(
      `${process.env.MEDUSA_BACKEND_URL || 'http://localhost:9000'}/store/auth/social/accounts`,
      {
        method: 'GET',
        headers: {
          'x-publishable-api-key': publishableKey,
          // Add authentication headers from cookies
          'Cookie': (await cookies()).toString(),
        },
      }
    )

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}))
      return { 
        success: false, 
        error: errorData.message || 'Failed to get social accounts' 
      }
    }

    const data = await response.json()
    return { success: true, data }
  } catch (error: any) {
    console.error('Get social accounts error:', error)
    return { 
      success: false, 
      error: error.message || 'Failed to get social accounts' 
    }
  }
}

