import crypto from 'crypto'
import { AbstractAuthModuleProvider, MedusaError } from '@medusajs/framework/utils'
import { AuthenticationInput, AuthenticationResponse, AuthIdentityProviderService, Logger } from '@medusajs/framework/types'

interface DiscordAuthConfig {
  clientId: string
  clientSecret: string
  callbackUrl: string
}

interface DiscordUserInfo {
  id: string
  username: string
  discriminator: string
  global_name?: string
  avatar?: string
  email?: string
  verified?: boolean
  locale?: string
}

export class DiscordAuthService extends AbstractAuthModuleProvider {
  static identifier = 'discord'
  static DISPLAY_NAME = 'Discord Authentication'

  protected config_: DiscordAuthConfig
  protected logger_: Logger

  static validateOptions(options: DiscordAuthConfig) {
    if (!options.clientId) {
      throw new Error('Discord clientId is required')
    }
    if (!options.clientSecret) {
      throw new Error('Discord clientSecret is required')
    }
    if (!options.callbackUrl) {
      throw new Error('Discord callbackUrl is required')
    }
  }

  constructor({ logger }: { logger: Logger }, options: DiscordAuthConfig) {
    // @ts-ignore
    super(...arguments)
    this.config_ = options
    this.logger_ = logger
  }

  async register(_: AuthenticationInput): Promise<AuthenticationResponse> {
    throw new MedusaError(
      MedusaError.Types.NOT_ALLOWED,
      'Discord does not support registration. Use method `authenticate` instead.'
    )
  }

  async authenticate(
    req: AuthenticationInput,
    authIdentityService: AuthIdentityProviderService
  ): Promise<AuthenticationResponse> {
    const query = req.query ?? {}
    const body = req.body ?? {}

    if (query.error) {
      return {
        success: false,
        error: `${query.error_description || query.error}`,
      }
    }

    const stateKey = crypto.randomBytes(32).toString('hex')
    const state = {
      callback_url: body?.callback_url ?? this.config_.callbackUrl,
    }

    await authIdentityService.setState(stateKey, state)

    return this.getRedirect(this.config_.clientId, state.callback_url, stateKey)
  }

  async validateCallback(
    req: AuthenticationInput,
    authIdentityService: AuthIdentityProviderService
  ): Promise<AuthenticationResponse> {
    const query = req.query ?? {}
    const body = req.body ?? {}

    if (query.error) {
      return {
        success: false,
        error: `${query.error_description || query.error}`,
      }
    }

    const code = query?.code ?? body?.code
    if (!code) {
      return { success: false, error: 'No code provided' }
    }

    const state = await authIdentityService.getState(query?.state as string)
    if (!state) {
      return { success: false, error: 'No state provided, or session expired' }
    }

    try {
      // Exchange code for access token
      const tokenResponse = await this.exchangeCodeForToken(
        code as string,
        state.callback_url as string
      )

      // Get user info from Discord API
      const userInfo = await this.getUserInfo(tokenResponse.access_token)

      if (!userInfo.email) {
        return {
          success: false,
          error: 'Email not provided by Discord. Ensure the "email" scope is granted.',
        }
      }

      // Verify and create/retrieve auth identity
      const result = await this.verify_(userInfo, authIdentityService)

      return result
    } catch (error) {
      return { success: false, error: error.message }
    }
  }

  private async verify_(
    userInfo: DiscordUserInfo,
    authIdentityService: AuthIdentityProviderService
  ) {
    const entity_id = userInfo.id
    const avatarUrl = userInfo.avatar
      ? `https://cdn.discordapp.com/avatars/${userInfo.id}/${userInfo.avatar}.png`
      : null

    const userMetadata = {
      email: userInfo.email,
      name: userInfo.global_name || userInfo.username,
      picture: avatarUrl,
      username: userInfo.username,
      discriminator: userInfo.discriminator,
      locale: userInfo.locale,
      verified: userInfo.verified,
    }

    let authIdentity

    try {
      authIdentity = await authIdentityService.retrieve({
        entity_id,
      })
    } catch (error) {
      if (error.type === MedusaError.Types.NOT_FOUND) {
        const createdAuthIdentity = await authIdentityService.create({
          entity_id,
          user_metadata: userMetadata,
        })
        authIdentity = createdAuthIdentity
      } else {
        return { success: false, error: error.message }
      }
    }

    return {
      success: true,
      authIdentity,
    }
  }

  private async exchangeCodeForToken(code: string, callbackUrl: string) {
    const response = await fetch('https://discord.com/api/oauth2/token', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        client_id: this.config_.clientId,
        client_secret: this.config_.clientSecret,
        code,
        grant_type: 'authorization_code',
        redirect_uri: callbackUrl,
      }),
    })

    if (!response.ok) {
      const error = await response.text()
      throw new MedusaError(
        MedusaError.Types.INVALID_DATA,
        `Could not exchange token, ${response.status}, ${error}`
      )
    }

    return response.json()
  }

  private async getUserInfo(accessToken: string): Promise<DiscordUserInfo> {
    const response = await fetch('https://discord.com/api/users/@me', {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    })

    if (!response.ok) {
      const error = await response.text()
      throw new MedusaError(
        MedusaError.Types.INVALID_DATA,
        `Failed to fetch Discord user info: ${error}`
      )
    }

    return response.json()
  }

  private getRedirect(clientId: string, callbackUrl: string, stateKey: string) {
    const authUrl = new URL('https://discord.com/api/oauth2/authorize')
    authUrl.searchParams.set('client_id', clientId)
    authUrl.searchParams.set('redirect_uri', callbackUrl)
    authUrl.searchParams.set('response_type', 'code')
    authUrl.searchParams.set('scope', 'identify email')
    authUrl.searchParams.set('state', stateKey)
    authUrl.searchParams.set('prompt', 'consent')

    return { success: true, location: authUrl.toString() }
  }
}

