import { useEffect } from 'react'
import { toast } from 'sonner'
import { loadIntent, loadExpiredIntent, clearIntent, readFlashCookie } from '@/lib/deferred-intent'

type ActionHandler = (payload: unknown) => Promise<void | { unavailable: true }>

export const ACTION_REGISTRY: Record<string, ActionHandler> = {}

export function DeferredActionExecutor() {
  useEffect(() => {
    // Handle flash cookie (hard-protected route redirect)
    const flash = readFlashCookie()
    if (flash === 'sign_in_required') {
      toast('Sign in to access your dashboard.')
    }

    // AC7: intent present but TTL expired — clear and toast
    const expiredIntent = loadExpiredIntent()
    if (expiredIntent) {
      clearIntent()
      toast('Signed in! Continue from here.')
      return
    }

    // Handle deferred intent within TTL
    const intent = loadIntent()
    if (!intent) return

    clearIntent()

    const handler = ACTION_REGISTRY[intent.action]

    if (!handler) {
      toast('Signed in! Continue from here.')
      return
    }

    handler(intent.payload)
      .then((result) => {
        if (result && result.unavailable) {
          toast('Signed in! The item is no longer available.')
