import { MedusaStoreRequest, MedusaResponse } from '@medusajs/framework/http'
import {
  ContainerRegistrationKeys,
  Modules,
  MedusaError
} from '@medusajs/framework/utils'
import { generateJwtToken } from '@medusajs/framework/utils'
import { AUTHENTICATION_MODULE } from '#/modules/authentication'
import SocialAccountManagementService from '#/modules/authentication/services/social-account-management.service'
import { emitAuthEvent, AuthEventType } from '#/modules/authentication/services/auth-event-emitter'

/**
 * POST /auth/refresh
 * Validates the refresh token from the _medusa_refresh cookie,
 * rotates it (single-use), and issues a new access + refresh token pair.
 */
export const POST = async (req: MedusaStoreRequest, res: MedusaResponse) => {
  const config = req.scope.resolve(ContainerRegistrationKeys.CONFIG_MODULE)
  const authModuleService = req.scope.resolve<SocialAccountManagementService>(
    AUTHENTICATION_MODULE
  )

  // Extract refresh token from cookie
  const refreshTokenCookie = req.cookies?.['_medusa_refresh']

  if (!refreshTokenCookie) {
    throw new MedusaError(
      MedusaError.Types.UNAUTHORIZED,
      'No refresh token provided'
    )
  }

  try {
    // Validate and rotate the refresh token
    const { rawToken: newRefreshToken, customerId } =
      await authModuleService.validateAndRotateRefreshToken(
        refreshTokenCookie,
        {
          ipAddress: (req.headers['x-forwarded-for'] as string) || req.ip,
          userAgent: req.headers['user-agent'] as string
        }
      )

    // Look up auth identity for this customer to include in JWT
    const authService = req.scope.resolve(Modules.AUTH)
    let authIdentityId: string | undefined
    try {
      const authIdentities = await authService.listAuthIdentities({
        app_metadata: { customer_id: customerId }
      })
      authIdentityId = authIdentities[0]?.id
    } catch {
      // Auth identity lookup failed — JWT will omit auth_identity_id
    }

    // Re-read platform_role from DB (never forward from old JWT — stale admin revocation)
    const platformRole = await authModuleService.getCustomerPlatformRole(customerId)

    // Generate new short-lived access token (15 minutes)
    const { http } = config.projectConfig
    const newAccessToken = generateJwtToken(
      {
        actor_id: customerId,
        actor_type: 'customer',
        ...(authIdentityId && { auth_identity_id: authIdentityId }),
        app_metadata: {
          customer_id: customerId,
          platform_role: platformRole
        }
      },
      {
        secret: http.jwtSecret,
        expiresIn: '15m'
      }
    )

    // Set new tokens as httpOnly cookies
    const isProduction = process.env.NODE_ENV === 'production'

    res.cookie('_medusa_jwt', newAccessToken, {
      httpOnly: true,
      secure: isProduction,
      sameSite: 'strict',
      maxAge: 15 * 60 * 1000, // 15 minutes
      path: '/'
    })

    res.cookie('_medusa_refresh', newRefreshToken, {
      httpOnly: true,
      secure: isProduction,
      sameSite: 'strict',
      maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
      path: '/'
    })

    // Emit TOKEN_REFRESH auth event (fire-and-forget)
    emitAuthEvent({
      customer_id: customerId,
      event_type: AuthEventType.TOKEN_REFRESH,
      ip_address: (req.headers['x-forwarded-for'] as string) || req.ip,
      user_agent: req.headers['user-agent'] as string
    })

    return res.json({ success: true })
  } catch (error) {
    // Clear auth cookies on refresh failure
    res.clearCookie('_medusa_jwt', { path: '/' })
    res.clearCookie('_medusa_refresh', { path: '/' })

    if (error instanceof MedusaError) {
      throw error
    }

    throw new MedusaError(
      MedusaError.Types.UNAUTHORIZED,
      'Invalid or expired refresh token'
    )
  }
}

import 'server-only';
import { cookies as nextCookies } from 'next/headers';

export const getAuthHeaders = async (): Promise<
  { authorization: string } | {}
> => {
  const cookieStore = await nextCookies();
  const token = cookieStore.get('_medusa_jwt')?.value;

  if (!token) {
    return {};
  }

  return { authorization: `Bearer ${token}` };
};

export const getCacheTag = async (
  tag: string
): Promise<string> => {
  try {
    const cookies = await nextCookies();
    const cacheId = cookies.get('_medusa_cache_id')?.value;

    if (!cacheId) {
      return '';
    }

    return `${tag}-${cacheId}`;
  } catch (error) {
    return '';
  }
};

export const getCacheOptions = async (
  tag: string
): Promise<{ tags: string[] } | {}> => {
  if (typeof window !== 'undefined') {
    return {};
  }

  const cacheTag = await getCacheTag(tag);

  if (!cacheTag) {
    return {};
  }

  return { tags: [`${cacheTag}`] };
};

export const setAuthToken = async (token: string) => {
  const cookies = await nextCookies();
  cookies.set('_medusa_jwt', token, {
    maxAge: 60 * 15, // 15 minutes
    httpOnly: true,
    sameSite: 'strict',
    secure: process.env.NODE_ENV === 'production',
    path: '/',
  });
};

export const setRefreshToken = async (token: string) => {
  const cookies = await nextCookies();
  cookies.set('_medusa_refresh', token, {
    maxAge: 60 * 60 * 24 * 30, // 30 days
    httpOnly: true,
    sameSite: 'strict',
    secure: process.env.NODE_ENV === 'production',
    path: '/',
  });
};

export const getRefreshToken = async (): Promise<string | undefined> => {
  const cookies = await nextCookies();
  return cookies.get('_medusa_refresh')?.value;
};

export const removeAuthToken = async () => {
  const cookies = await nextCookies();
  cookies.set('_medusa_jwt', '', { maxAge: -1, path: '/' });
};

export const removeRefreshToken = async () => {
  const cookies = await nextCookies();
  cookies.set('_medusa_refresh', '', { maxAge: -1, path: '/' });
};

export const removeAllAuthCookies = async () => {
  const cookies = await nextCookies();
  cookies.set('_medusa_jwt', '', { maxAge: -1, path: '/' });
  cookies.set('_medusa_refresh', '', { maxAge: -1, path: '/' });
};

export const getCartId = async () => {
  const cookies = await nextCookies();
  return cookies.get('_medusa_cart_id')?.value;
};

export const setCartId = async (cartId: string) => {
