    maxAge: -1,
  });
};

import { Request, Response, NextFunction } from 'express'
import jwt from 'jsonwebtoken'
import { config } from '../config/env'
import { logger } from '../config/logger'
import { handleAuthError, createErrorResponse, ErrorCodes } from '../utils/error-response'
import { AppDataSource } from '../config/database'
import { UserProfile } from '../entities/UserProfile'

export interface AuthenticatedRequest extends Request {
  user?: {
    id: string
    email: string
    actor_id: string
    actor_type: string
    auth_identity_id: string
    platformRole: string | null
  }
}

export interface JWTPayload {
  actor_id: string
  actor_type: string
  auth_identity_id: string
  app_metadata?: {
    customer_id?: string
    platform_role?: string | null
  }
  iat?: number
  exp?: number
}

/**
 * Middleware to authenticate requests using JWT tokens.
 * Extracts user information from the Authorization header.
 * Checks JWT iat against sessionInvalidatedAt to reject tokens issued before session invalidation.
 */
export const authenticateToken = async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const authHeader = req.headers.authorization
    const token = authHeader && authHeader.startsWith('Bearer ') ? authHeader.substring(7) : null

    if (!token) {
      logger.warn('Authentication failed: No token provided', {
        headers: req.headers,
        userAgent: req.get('User-Agent'),
        ip: req.ip
      })
      return res.status(401).json(createErrorResponse(
        ErrorCodes.AUTH_TOKEN_MISSING,
        'Access token required'
      ))
    }

    // Verify JWT token
    const decoded = jwt.verify(token, config.JWT_SECRET) as JWTPayload

    if (!decoded.actor_id || decoded.actor_type !== 'customer') {
      logger.warn('Authentication failed: Invalid token format', {
        tokenPayload: {
          actor_id: decoded.actor_id,
          actor_type: decoded.actor_type,
          hasCustomerId: !!decoded.app_metadata?.customer_id
        },
        userAgent: req.get('User-Agent'),
        ip: req.ip
      })
      return res.status(401).json(createErrorResponse(
        ErrorCodes.AUTH_TOKEN_INVALID,
        'Invalid token format or not a customer token'
      ))
    }

    const customerId = decoded.app_metadata?.customer_id || decoded.actor_id

    // Check if the token was issued before session invalidation
    const sessionValid = await isTokenSessionValid(customerId, decoded.iat)
    if (!sessionValid) {
      logger.warn('Authentication failed: Token issued before session invalidation', {
        customerId,
        tokenIat: decoded.iat
      })
      return res.status(401).json(createErrorResponse(
        ErrorCodes.AUTH_TOKEN_INVALID,
        'Session has been invalidated'
      ))
    }

    // Extract user information from token
    req.user = {
      id: customerId,
      email: '', // We don't have email in JWT, will need to fetch if needed
      actor_id: decoded.actor_id,
      actor_type: decoded.actor_type,
      auth_identity_id: decoded.auth_identity_id,
      platformRole: decoded.app_metadata?.platform_role ?? null
    }

    next()
  } catch (error) {
    return handleAuthError(
      res,
      error as Error,
      req.get('User-Agent'),
      req.ip
    )
  }
}

/**
 * Check if a JWT was issued before the user's session was invalidated.
 * Returns true if the token is still valid (no invalidation or issued after invalidation).
 */
async function isTokenSessionValid(customerId: string, iat?: number): Promise<boolean> {
  if (!iat) return true
  const profileRepo = AppDataSource.getRepository(UserProfile)
  const profile = await profileRepo.findOne({
    where: { customerId },
    select: ['sessionInvalidatedAt']
  })
  if (!profile?.sessionInvalidatedAt) return true
  const invalidatedAtSeconds = Math.floor(profile.sessionInvalidatedAt.getTime() / 1000)
  return iat >= invalidatedAtSeconds
}

/**
 * Optional authentication middleware - doesn't fail if no token provided
 * Sets req.user if valid token is present, checks session invalidation
 */
export const optionalAuth = async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
  try {
    const authHeader = req.headers.authorization
    const token = authHeader && authHeader.startsWith('Bearer ') ? authHeader.substring(7) : null

    if (!token) {
      // No token provided, continue without authentication
      return next()
    }

    // Verify JWT token
    const decoded = jwt.verify(token, config.JWT_SECRET) as JWTPayload

    if (decoded.actor_id && decoded.actor_type === 'customer') {
      const customerId = decoded.app_metadata?.customer_id || decoded.actor_id

      // Check session invalidation before populating req.user
      const valid = await isTokenSessionValid(customerId, decoded.iat)
      if (!valid) {
        return next()
      }

      req.user = {
        id: customerId,
        email: '',
        actor_id: decoded.actor_id,
        actor_type: decoded.actor_type,
        auth_identity_id: decoded.auth_identity_id,
        platformRole: decoded.app_metadata?.platform_role ?? null
      }
    }

    next()
  } catch (error) {
    // If token is invalid, continue without authentication rather than failing
    logger.warn('Optional auth failed, continuing without user context', {
      error: (error as Error).message
    })
    next()
  }
}

/**
 * Middleware that enforces platform admin access.
 * Returns HTTP 403 if the authenticated user's platformRole is not 'admin'.
 */
export const requirePlatformAdmin = (req: AuthenticatedRequest, res: Response, next: NextFunction): void => {
  if (req.user?.platformRole !== 'admin') {
    logger.warn('Platform admin access denied', {
      platformRole: req.user?.platformRole ?? null,
      userId: req.user?.id ?? null,
      path: (req as any).path,
      ip: req.ip
    })
    res.status(403).json({ error: 'insufficient_permissions' })
    return
  }
  next()
}

