          >
            {item.label}
            {item.label === "Messages" && Boolean(unreads?.length) && (
              <span
                className="absolute top-3 left-24 w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-bold text-white"
                style={{ background: "var(--brand-primary, #8B5CF6)" }}
              >
                {unreads?.length}
              </span>
            )}
          </NavigationItem>
        ))}
      </div>
      <div style={{ borderTop: "1px solid var(--border-default, #2C2A4A)" }} className="py-2">
        <NavigationItem
          href="/user/settings"
          active={path === "/user/settings"}
        >
          Settings
        </NavigationItem>
      </div>
    </nav>
  )
}
